INSERT INTO `admission_guide` VALUES (17, 2, 2026, '北京大学2026年招生简章', '金融学专业招收80人，最低分675', '北大简章.pdf', NULL, 0, NULL, NULL, 0, NULL, 0, 0, 1, '2026-06-18 11:20:15', NULL);
INSERT INTO `admission_guide` VALUES (21, 1, 2025, '武汉纺织大学2025招生简章', '武汉纺织大学是公办全日制本科院校，中央与湖北省共建，拥有完整学士、硕士、博士学位授予权，国标代码 10495，湖北志愿代码 C117，设有阳光、南湖、东湖三大校区，纺织、服装设计、设计类为特色王牌专业。\n学校面向全国招收普通高考考生，新高考考生需符合专业选考要求，色觉异常限报设计、纺织相关专业。录取认可各省政策性加分，实行分数优先原则分配专业，不服从专业调剂且无法满足所填专业予以退档；艺术类采用各省统考成绩投档录取。\n学费按湖北省物价标准收取，校内建立完善奖助体系，设有国家奖助学金、校级奖学金、助学贷款、勤工助学等帮扶政策。新生按时报到，入学三个月进行资格复查，合格者颁发本科毕业证及对应学士学位。\n学校未委托校外中介招生，招生咨询可登录本科招生网https://zjc.wtu.edu.cn/，联系邮箱zjc@wtu.edu.cn，咨询电话 027-59367521、59367524。', '武汉纺织大学_招生简章.pdf', 'http://localhost:8080/file/view/0acd1b55-833a-4b22-addd-4a0ea9e098ad.pdf', 1, NULL, 1, 1, '2026-06-18 17:02:32', 0, 0, 0, '2026-06-18 12:46:55', NULL);
INSERT INTO `admission_guide` VALUES (22, 3, 2025, '武汉大学2025招生简章', '武汉纺织大学是公办全日制本科院校，中央与湖北省共建，拥有完整学士、硕士、博士学位授予权，国标代码 10495，湖北志愿代码 C117，设有阳光、南湖、东湖三大校区，纺织、服装设计、设计类为特色王牌专业。\n学校面向全国招收普通高考考生，新高考考生需符合专业选考要求，色觉异常限报设计、纺织相关专业。录取认可各省政策性加分，实行分数优先原则分配专业，不服从专业调剂且无法满足所填专业予以退档；艺术类采用各省统考成绩投档录取。\n学费按湖北省物价标准收取，校内建立完善奖助体系，设有国家奖助学金、校级奖学金、助学贷款、勤工助学等帮扶政策。新生按时报到，入学三个月进行资格复查，合格者颁发本科毕业证及对应学士学位。\n学校未委托校外中介招生，招生咨询可登录本科招生网https://zjc.wtu.edu.cn/，联系邮箱zjc@wtu.edu.cn，咨询电话 027-59367521、59367524。', '武汉纺织大学_招生简章.pdf', 'http://localhost:8080/file/view/0acd1b55-833a-4b22-addd-4a0ea9e098ad.pdf', 0, NULL, 0, 0, '2026-06-18 17:02:32', 0, 0, 0, '2026-06-18 12:46:55', NULL);
