INSERT INTO `institution` VALUES (1, '10495', '武汉纺织大学', 1, '420000', '420100', '湖北省武汉市洪山区民族大道纺织路1号', '普通', 1, '027-59367520', 'zjc@wtu.edu.cn', 'https://www.wtu.edu.cn/', 'https://cdn.urongda.com//images/normal/medium/wuhan-textile-university-logo-1024px.png', '武汉纺织大学始建于 1958 年，2010 年定名，坐落武汉，是中西部基础能力建设高校、全国十大时装名校。以纺织、设计为王牌，纺织学科稳居世界前列，三学科进入 ESI 前 1%，拥有自主培养工程院院士。覆盖工、艺、经、管等门类，三大校区，本科与完整硕博培养体系，深耕纺织新材料研发，产出嫦娥探月国旗等重大成果，践行 “崇真尚美，笃行致远” 校训。', 1, 1, '2026-06-18 12:20:42', '2026-06-24 17:03:07', NULL);
INSERT INTO `institution` VALUES (2, '10524', '中南民族大学', 1, '420000', '420100', '湖北省武汉市洪山区民族大道182号', '普通', 1, '027-67842763', 'zb@scuec.edu.cn', 'https://www.scuec.edu.cn', 'https://cdn.urongda.com//images/normal/medium/south-central-minzu-university-logo-1024px.png', '国家民委直属公办综合性本科高校，国家民委、教育部、湖北省共建，湖北省级双一流建设高校，1951年建校，民族学、化学、文学学科实力突出，拥有博士点与博士后流动站，南湖校园民族特色浓厚。', 1, 1, '2026-06-11 12:18:22', '2026-06-17 16:28:28', NULL);
INSERT INTO `institution` VALUES (3, '10486', '武汉大学', 1, '420000', '420100', '湖北省武汉市武昌区珞珈山', '985', 1, '027-68754231', 'zs@whu.edu.cn', 'https://www.whu.edu.cn', 'https://cdn.urongda.com//images/normal/medium/wuhan-university-logo-1024px.png', '教育部直属全国重点大学，始建于1893年自强学堂，985、211、双一流高校，综合实力强劲，文理工医均衡发展，珞珈山校园环境优美。', 1, 1, '2026-06-11 12:30:40', '2026-06-17 16:29:37', NULL);
