  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '详细地址',
  `level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '普通' COMMENT '层次：985/211/双一流/普通',
  `nature` tinyint(0) UNSIGNED NOT NULL DEFAULT 1 COMMENT '1-公办 2-民办',
