  `logo_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '院校Logo',
  `introduction` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '院校简介',
  `is_online` tinyint(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0-下线 1-上线',
  `status` tinyint(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0-待审核 1-已通过 2-已拒绝 3-已禁用',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
