CREATE TABLE `region`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '区域ID',
  `code` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '区域代码（如省代码110000）',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '区域名称',
  `level` tinyint(0) UNSIGNED NOT NULL COMMENT '层级：1-省 2-市',
  `parent_id` bigint(0) UNSIGNED NULL DEFAULT 0 COMMENT '父级ID，省级为0',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_code`(`code`) USING BTREE,
  INDEX `idx_parent`(`parent_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 34 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '省份/城市字典表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of region
-- ----------------------------

-- ----------------------------
-- Table structure for role
-- ----------------------------
DROP TABLE IF EXISTS `role`;
CREATE TABLE `role`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '角色ID',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '角色名称',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '角色编码（代码权限判断用）',
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '描述',
  `status` tinyint(0) UNSIGNED NOT NULL DEFAULT 1 COMMENT '0-禁用 1-正常',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_code`(`code`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '角色表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of role
-- ----------------------------

-- ----------------------------
-- Table structure for score_rank
-- ----------------------------
DROP TABLE IF EXISTS `score_rank`;
CREATE TABLE `score_rank`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `year` smallint(0) UNSIGNED NOT NULL COMMENT '年份',
  `subject_type` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '科类：物理类/历史类',
  `score_min` smallint(0) UNSIGNED NOT NULL COMMENT '分数下界',
  `score_max` smallint(0) UNSIGNED NOT NULL COMMENT '分数上界（与score_min相同表示单分；不同表示合并段如695-750）',
  `score_label` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '原始分数标签：如\"691\"或\"695-750\"',
  `segment_count` int(0) UNSIGNED NOT NULL COMMENT '本段人数',
  `cumulative_count` int(0) UNSIGNED NOT NULL COMMENT '累计人数（位次）：该分数及以上全省总人数',
  `province_code` char(6) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '420000' COMMENT '省份代码（湖北=420000）',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_year_sub_score`(`year`, `subject_type`, `score_min`, `score_max`) USING BTREE,
  INDEX `idx_year_sub_cum`(`year`, `subject_type`, `cumulative_count`) USING BTREE,
  INDEX `idx_year_sub_score`(`year`, `subject_type`, `score_max`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3447 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '高考一分一段表（位次表）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of score_rank
-- ----------------------------

-- ----------------------------
-- Table structure for student_score
-- ----------------------------
DROP TABLE IF EXISTS `student_score`;
CREATE TABLE `student_score`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(0) UNSIGNED NOT NULL COMMENT '用户ID',
  `province_code` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '省份代码',
  `exam_year` smallint(0) UNSIGNED NOT NULL COMMENT '高考年份',
  `subject_type` tinyint(0) UNSIGNED NOT NULL COMMENT '1-物理/理 2-历史/文',
  `selected_subjects` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '选科组合（如\"物化生\"）',
  `total_score` int(0) UNSIGNED NOT NULL COMMENT '高考总分',
  `province_rank` int(0) UNSIGNED NOT NULL COMMENT '省内位次',
  `equivalent_score` decimal(6, 2) NULL DEFAULT NULL COMMENT '等位分',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user`(`user_id`) USING BTREE,
  INDEX `idx_province_year`(`province_code`, `exam_year`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '考生成绩表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of student_score
-- ----------------------------

-- ----------------------------
-- Table structure for subject_dict
-- ----------------------------
DROP TABLE IF EXISTS `subject_dict`;
CREATE TABLE `subject_dict`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `code` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '科目代码',
  `name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '科目名称',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_code`(`code`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '选科字典表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of subject_dict
-- ----------------------------

-- ----------------------------
-- Table structure for user
-- ----------------------------
DROP TABLE IF EXISTS `user`;
CREATE TABLE `user`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '用户ID',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '手机号',
  `password_hash` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '密码哈希（bcrypt）',
  `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '昵称',
  `avatar_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '头像',
  `wechat_openid` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '微信OpenID',
  `status` tinyint(0) UNSIGNED NOT NULL DEFAULT 1 COMMENT '0-禁用 1-正常',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_phone`(`phone`) USING BTREE,
  UNIQUE INDEX `uk_wechat`(`wechat_openid`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 17 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '考生用户表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of user
-- ----------------------------

-- ----------------------------
-- Table structure for volunteer_plan
-- ----------------------------
DROP TABLE IF EXISTS `volunteer_plan`;
CREATE TABLE `volunteer_plan`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(0) UNSIGNED NOT NULL COMMENT '用户ID',
  `plan_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '方案名称',
  `is_locked` tinyint(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0-未锁定 1-已锁定',
  `status` tinyint(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0-草稿 1-已确认',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 35 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '志愿方案表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of volunteer_plan
-- ----------------------------

-- ----------------------------
-- Table structure for volunteer_plan_detail
-- ----------------------------
DROP TABLE IF EXISTS `volunteer_plan_detail`;
CREATE TABLE `volunteer_plan_detail`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `plan_id` bigint(0) UNSIGNED NOT NULL COMMENT '所属志愿方案ID',
  `institution_id` bigint(0) UNSIGNED NOT NULL COMMENT '院校ID',
  `enrollment_plan_id` bigint(0) UNSIGNED NOT NULL COMMENT '招生计划ID',
  `sort_order` int(0) UNSIGNED NOT NULL COMMENT '志愿排序（第几志愿）',
  `probability` decimal(5, 2) NULL DEFAULT NULL COMMENT '录取概率(%)',
  `risk_level` tinyint(0) UNSIGNED NOT NULL COMMENT '1-冲 2-稳 3-保',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_plan`(`plan_id`) USING BTREE,
  INDEX `idx_institution`(`institution_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 528 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '志愿方案详情表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of volunteer_plan_detail
-- ----------------------------

